import React, { useState } from "react";
import { motion } from "framer-motion";


export function ShowcaseCarousel() {

    const [index, setIndex] = useState(0);
  const items = [
    {
      sectionTitle: "Things I have developed in several domains",
      title: "Chat App",
      description: "Real-time messaging app with modern UI",
      image: "https://via.placeholder.com/600x300",
      live: "#",
      code: "#",
    },
    {
      title: "Finance Tracker",
      description: "Track expenses and analytics",
      image: "https://via.placeholder.com/600x300",
    },
  ];

    const next = () => {
      setIndex((prev) => (prev + 1) % items.length);
    };

    const prev = () => {
      setIndex((prev) => (prev - 1 + items.length) % items.length);
    };

    if (!items.length) return null;

    const current = items[index];

    return (
      <div className="py-20 text-center">
        <h2 className="text-3xl font-semibold mb-10">
          {current.sectionTitle || "Things I have developed"}
        </h2>

        <div className="relative max-w-4xl mx-auto">
          {/* Left Arrow */}
          <button
            onClick={prev}
            className="absolute left-0 top-1/2 -translate-y-1/2 text-3xl px-4"
          >
            ←
          </button>

          {/* Card */}
          <motion.div
            key={index}
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.4 }}
            className="bg-white/10 backdrop-blur-lg rounded-2xl shadow-xl p-6"
          >
            <img
              src={current.image}
              alt={current.title}
              className="w-full h-[300px] object-cover rounded-xl"
            />

            <h3 className="text-xl font-semibold mt-4">
              {current.title}
            </h3>

            <p className="text-gray-400 text-sm mt-2">
              {current.description}
            </p>

            <div className="mt-4 flex justify-center gap-4">
              {current.live && (
                <a href={current.live} target="_blank" rel="noreferrer">
                  <button className="px-4 py-2 rounded-lg bg-indigo-500">
                    Live
                  </button>
                </a>
              )}

              {current.code && (
                <a href={current.code} target="_blank" rel="noreferrer">
                  <button className="px-4 py-2 rounded-lg border">
                    Code
                  </button>
                </a>
              )}
            </div>
          </motion.div>

          {/* Right Arrow */}
          <button
            onClick={next}
            className="absolute right-0 top-1/2 -translate-y-1/2 text-3xl px-4"
          >
            →
          </button>
        </div>

        {/* Dots */}
        <div className="flex justify-center gap-2 mt-6">
          {items.map((_, i) => (
            <div
              key={i}
              onClick={() => setIndex(i)}
              className={`h-2 w-2 rounded-full cursor-pointer ${
                i === index ? "bg-white" : "bg-gray-500"
              }`}
            />
          ))}
        </div>
      </div>
    );
  }
